class Solution {
public:
    string crackSafe(int n, int k) {
        int target = pow(k, n);
        string res = "";
        for (int i = 0; i < n; i++) res += '0';
        unordered_set<string> visited;
        dfs(res, n, k, visited, res);
        return res;
    }

    void dfs(string node, int n, int k, unordered_set<string> &visited, string &res) {
        for (int i = 0; i < k; i++) {
            string next_node = node.substr(1, n - 1) + (char)('0' + i);
            if (visited.find(next_node) == visited.end()) {
                visited.insert(next_node);
                res += (char)('0' + i);
                dfs(next_node, n, k, visited, res);
            }
        }
    }
};

